import psycopg2

def connect():
    return psycopg2.connect(
        host="your_host",
        database="your_database",
        user="your_user",
        password="your_password"
    )

def search_users(username=None, email=None, role=None, status=None, conn=None):
    query = """
        SELECT * FROM users
        WHERE 1=1
    """

    params = []

    if username:
        query += " AND username=%s"
        params.append(username)

    if email:
        query += " AND email=%s"
        params.append(email)

    if role:
        query += " AND role=%s"
        params.append(role)

    if status:
        query += " AND status=%s"
        params.append(status)

    cursor = conn.cursor()
    cursor.execute(query, params)
    result = cursor.fetchall()
    return result

